  9	/// <summary>Persists workspace-scoped products with SQL Server uniqueness handling.</summary>
 10	public sealed class EfProductCatalog(ApplicationDbContext dbContext) : IProductCatalog
 11	{
 12	    /// <inheritdoc />
 13	    public async Task<Product> CreateAsync(Product product, CancellationToken cancellationToken)
 14	    {
 15	        dbContext.Products.Add(product);
 16	        try
 17	        {
 18	            await dbContext.SaveChangesAsync(cancellationToken);
 19	            return product;
 20	        }
 21	        catch (DbUpdateException exception) when (exception.InnerException is SqlException { Number: 2601 or 2627 })
 22	        {
 23	            throw new ProductSkuConflictException();
 24	        }
 25	    }
 26	
 27	    /// <inheritdoc />
 28	    public async Task<IReadOnlyList<Product>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken) =>
 29	        await dbContext.Products.AsNoTracking().Where(item => item.WorkspaceId == workspaceId && item.ArchivedAtUtc == null)
 30	            .OrderBy(item => item.Name).ThenBy(item => item.Id).ToListAsync(cancellationToken);
 31	
 32	    /// <inheritdoc />
 33	    public Task<Product?> FindAsync(Guid workspaceId, Guid productId, CancellationToken cancellationToken) =>
 34	        dbContext.Products.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId && item.Id == productId, cancellationToken);
 35	
 36	    /// <inheritdoc />
 37	    public async Task SaveChangesAsync(CancellationToken cancellationToken) => await dbContext.SaveChangesAsync(cancellationToken);
 38	}
