  7	/// <summary>Configures product persistence.</summary>
  8	public sealed class ProductConfiguration : IEntityTypeConfiguration<Product>
  9	{
 10	    /// <inheritdoc />
 11	    public void Configure(EntityTypeBuilder<Product> builder)
 12	    {
 13	        builder.ToTable("Products");
 14	        builder.HasKey(product => product.Id);
 15	        builder.Property(product => product.Name).HasMaxLength(Product.NameMaxLength).IsRequired();
 16	        builder.Property(product => product.Sku).HasMaxLength(Product.SkuMaxLength).IsRequired();
 17	        builder.Property(product => product.CreatedAtUtc).IsRequired();
 18	        builder.HasIndex(product => new { product.WorkspaceId, product.Sku }).IsUnique();
 19	        builder.HasIndex(product => new { product.WorkspaceId, product.ArchivedAtUtc, product.Name, product.Id });
 20	        builder.HasOne<Workspace>().WithMany().HasForeignKey(product => product.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
 21	    }
 22	}
