  8	namespace InventoryFlow.Api.ExceptionHandling;
  9	
 10	/// <summary>
 11	/// Converts unhandled application exceptions into RFC 7807 problem details responses.
 12	/// </summary>
 13	/// <param name="logger">The logger used to capture unexpected failures.</param>
 14	public sealed class GlobalExceptionHandler(
 15	    ILogger<GlobalExceptionHandler> logger) : IExceptionHandler
 16	{
 17	    /// <inheritdoc />
 18	    public async ValueTask<bool> TryHandleAsync(
 19	        HttpContext httpContext,
 20	        Exception exception,
 21	        CancellationToken cancellationToken)
 22	    {
 23	        if (httpContext.Response.HasStarted)
 24	        {
 25	            logger.LogWarning(
 26	                exception,
 27	                "The response has already started for {RequestMethod} {RequestPath}",
 28	                httpContext.Request.Method,
 29	                httpContext.Request.Path);
 30	
 31	            return false;
 32	        }
 33	
 34	        var statusCode = exception switch
 35	        {
 36	            ValidationException => StatusCodes.Status400BadRequest,
 37	            DomainException => StatusCodes.Status400BadRequest,
 38	            AuthenticationException => StatusCodes.Status401Unauthorized,
 39	            ProductSkuConflictException => StatusCodes.Status409Conflict,
 40	            _ => StatusCodes.Status500InternalServerError,
 41	        };
 42	
 43	        logger.LogError(
 44	            exception,
 45	            "Unhandled exception while processing {RequestMethod} {RequestPath}",
 46	            httpContext.Request.Method,
 47	            httpContext.Request.Path);
 48	
 49	        if (exception is ValidationException validationException)
 50	        {
 51	            var validation = new ValidationProblemDetails(validationException.Errors.GroupBy(error => error.PropertyName).ToDictionary(group => group.Key, group => group.Select(error => error.ErrorMessage).ToArray()))
 52	            { Status = statusCode, Title = "One or more validation errors occurred.", Type = "https://tools.ietf.org/html/rfc9110#section-15.5.1" };
 53	            httpContext.Response.StatusCode = statusCode;
 54	            await httpContext.Response.WriteAsJsonAsync(validation, options: null, contentType: "application/problem+json", cancellationToken: cancellationToken);
 55	            return true;
 56	        }
 57	
 58	        var problemDetails = new ProblemDetails
 59	        {
 60	            Status = statusCode,
 61	            Title = statusCode switch { StatusCodes.Status400BadRequest => "A business rule was violated.", StatusCodes.Status401Unauthorized => "Authentication failed.", StatusCodes.Status409Conflict => "A product with this SKU already exists.", _ => "An unexpected error occurred." },
 62	            Type = statusCode switch
 63	            {
 64	                StatusCodes.Status400BadRequest => "https://tools.ietf.org/html/rfc9110#section-15.5.1",
 65	                StatusCodes.Status409Conflict => "https://tools.ietf.org/html/rfc9110#section-15.5.10",
 66	                _ => "https://tools.ietf.org/html/rfc9110#section-15.6.1",
 67	            },
 68	            Detail = exception is DomainException ? exception.Message : null,
 69	        };
 70	
 71	        httpContext.Response.StatusCode = statusCode;
 72	        await httpContext.Response.WriteAsJsonAsync(
 73	            problemDetails,
 74	            options: null,
 75	            contentType: "application/problem+json",
 76	            cancellationToken: cancellationToken);
 77	
 78	        return true;
 79	    }
 80	}
